         "Set the OPENAI_API_KEY environment variable.");

 var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
     ?? "gpt-4o-mini-2024-07-18";

 // --- Provider layer: concrete OpenAI client behind the MEAI abstraction ---
 IChatClient chatClient = new OpenAI.Chat.ChatClient(modelId, apiKey)
     .AsIChatClient();

 // --- Shared state for the note-taking tool ---
 var notebook = new Notebook();
 using var httpClient = new HttpClient();
 httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

 // --- Tool definitions ---
 var tools = new List<AITool>
 {
     AIFunctionFactory.Create(
         (
             [Description("The search query to look up on the web")]
             string query
         ) => WebSearchAsync(query, httpClient),
         nameof(WebSearchAsync),
         "Searches the web and returns the top result snippets for the query."),

     AIFunctionFactory.Create(notebook.TakeNote,
         nameof(notebook.TakeNote),
         "Records a research note or key finding for later summarization."),

     AIFunctionFactory.Create(notebook.GetNotes,
         nameof(notebook.GetNotes),
         "Retrieves all research notes taken so far."),
 };

 // --- Agent setup (orchestration layer) ---
 var agent = new ChatClientAgent(
     chatClient,
     instructions: """
         You are a thorough research assistant. When given a topic:

         1. **Search** – Use the WebSearchAsync tool multiple times with varied queries
            to gather comprehensive, diverse information about the topic.
         2. **Record** – After each useful search, call TakeNote to capture the key
            facts, statistics, or quotes you found.
         3. **Review** – Call GetNotes to see everything you have collected.
         4. **Summarize** – Produce a well-organized summary of your findings with
            clear sections. Cite sources where possible.

         Aim for at least 3 different search queries before summarizing.
         """,
     name: "ResearchAgent",
     description: "Researches a topic using web search and note-taking tools.",
     tools: tools);

 // --- Interactive loop ---
 Console.WriteLine("╔══════════════════════════════════════╗");
 Console.WriteLine("║       🔬 AI Research Agent           ║");
 Console.WriteLine("╚══════════════════════════════════════╝");
 Console.WriteLine("Enter a topic to research (or 'quit' to exit).\n");

 var session = await agent.CreateSessionAsync();

 while (true)
 {
     Console.Write("Topic> ");
     var topic = Console.ReadLine()?.Trim();

     if (string.IsNullOrEmpty(topic))
         continue;
     if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
         break;

     notebook.Clear();
     Console.WriteLine($"\n🔍 Researching: {topic}\n");

     await foreach (var update in agent.RunStreamingAsync(
         $"Research the following topic and provide a comprehensive summary: {topic}",
         session))
     {
         if (update.Text is { Length: > 0 } text)
             Console.Write(text);
     }

     Console.WriteLine("\n");
 }

 // ──────────────────────────── Tool implementations ────────────────────────────

 static async Task<string> WebSearchAsync(string query, HttpClient http)
 {
     Console.WriteLine($"  🌐 Searching: \"{query}\"");

     try
     {
         var url = $"https://html.duckduckgo.com/html/?q={Uri.EscapeDataString(query)}";
         var html = await http.GetStringAsync(url);

         // Extract result snippets
         var snippets = Regex.Matches(
                 html,
                 @"<a class=""result__snippet""[^>]*>(.*?)</a>",
                 RegexOptions.Singleline)
             .Cast<Match>()
             .Take(5)
             .Select(m => WebUtility.HtmlDecode(
                 Regex.Replace(m.Groups[1].Value, "<.*?>", "")).Trim())
             .Where(s => !string.IsNullOrWhiteSpace(s))
             .ToList();

         // Extract titles
         var titles = Regex.Matches(
                 html,
                 @"<a rel=""nofollow"" class=""result__a""[^>]*>(.*?)</a>",
                 RegexOptions.Singleline)
             .Cast<Match>()
             .Take(5)
             .Select(m => WebUtility.HtmlDecode(
                 Regex.Replace(m.Groups[1].Value, "<.*?>", "")).Trim())
             .ToList();

         if (snippets.Count == 0)
             return $"No results found for '{query}'.";

         var sb = new StringBuilder();
         for (var i = 0; i < snippets.Count; i++)
         {
             var title = i < titles.Count ? titles[i] : $"Result {i + 1}";
             sb.AppendLine($"- [{title}]: {snippets[i]}");
         }

         return sb.ToString();
     }
     catch (Exception ex)
     {
         return $"Search failed: {ex.Message}";
     }
 }

 // ──────────────────────────── Notebook helper ─────────────────────────────────

 sealed class Notebook
 {
     private readonly List<string> _notes = [];

     public string TakeNote(
         [Description("The note content to record")] string note)
     {
         _notes.Add(note);
         Console.WriteLine($"  📝 Note #{_notes.Count} recorded");
         return $"Note #{_notes.Count} saved.";
     }

     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes recorded yet.";

         Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");
         return string.Join('\n',
             _notes.Select((n, i) => $"{i + 1}. {n}"));
     }

     public void Clear() => _notes.Clear();
 }

